'''
'''
class Solution {
public:
    unordered_map<string, pair<string, double>> entries;
    pair<string, double> find(string x) {
        if (!entries.count(x)) {
            entries[x] = make_pair(x, 1);
        }
        if (entries[x].first != x) { // lazy evaluate
            auto rootEnt = find(entries[x].first);
            entries[x] = make_pair(rootEnt.first, entries[x].second * rootEnt.second);
        }

        return entries[x];
    }
    '''
    void unionSet(string x, string y, double quotient) {
        auto xrootEnt = find(x);
        auto yrootEnt = find(y);
        if (xrootEnt.first != yrootEnt.first) {
            entries[xrootEnt.first] = make_pair(yrootEnt.first, yrootEnt.second * quotient / xrootEnt.second);
        }
    }

    vector<double> calcEquation(vector<vector<string>>& equations, vector<double>& values, vector<vector<string>>& queries) {
        vector<double> ans;
        int n = values.size();
        int m = queries.size();
        for (int i = 0; i < n; i++) {
            auto eq = equations[i];
            unionSet(eq[0], eq[1], values[i]);
        }

        for (int i = 0; i < m; i++) {
            auto query = queries[i];
            string d1 = query[0];
            string d2 = query[1];
            if (!entries.count(d1) || !entries.count(d2)) 
                ans.push_back(-1);
            else {
                auto d1root = find(d1);
                auto d2root = find(d2);
                if (d1root.first != d2root.first)
                    ans.push_back(-1);
                else
                    ans.push_back(d1root.second / d2root.second);
            }
        }
        return ans;
    }
};
